onClick:
{{
  (() => {
    // 1. Valida se o número da denúncia foi preenchido
    if (!n_denuncia_Geral.text) {
      return showAlert('Por favor, preencha o número da denúncia.', 'warning');
    }

    // 2. Valida se o texto da denúncia foi preenchido
    if (!Text_den_Geral.text) {
      return showAlert('Por favor, preencha a descrição/texto da denúncia.', 'warning');
    }

    // 3. Dispara o processo de salvamento e limpa os campos informados após o sucesso
    return fotos_animais.cadastrarComImagens()
      .then(() => {
        // Lista com os nomes exatos de todos os componentes fornecidos para limpeza
        const camposParaLimpar = [
          "n_denuncia_Geral",
          "data_e_hora_denuncia",
          "Resposta_Denunciante",
          "classif_denun",
          "telefone_Geral",
          "email_Geral",
          "Denunciante_Geral",
          "Agressor_Geral",
          "Testemunha_Geral",
          "Select_cidade",
          "Text_den_Geral"
        ];

        // Executa a limpeza individual de cada componente de forma segura
        camposParaLimpar.forEach(async (campo) => {
          try {
            await resetWidget(campo, true);
          } catch(e) {
            // Ignora caso o widget não seja encontrado ou falte na tela
          }
        });

        showAlert('Denúncia Geral cadastrada e campos limpos com sucesso!', 'success');
      })
      .catch((err) => {
        showAlert('Erro ao salvar as informações: ' + (err?.message || err), 'error');
      });
  })()
}}
